parameters.functionCode:
// Generate comprehensive report
const client = $node[&quot;Get Active Clients&quot;].json;
const taskStats = $node[&quot;Get Task Statistics&quot;].json[0];
const statusBreakdown = $node[&quot;Get Status Breakdown&quot;].json;
const teamPerformance = $node[&quot;Get Team Performance&quot;].json;
const priorityBreakdown = $node[&quot;Get Priority Breakdown&quot;].json;

const reportData = {
  report_id: `task_report_${client.id}_${Date.now()}`,
  client_id: client.id,
  client_name: client.name,
  report_type: 'daily_task_summary',
  report_period: '7_days',
  generated_at: $now.toISO(),
  summary: {
    total_tasks: taskStats.total_tasks,
    completion_rate: taskStats.total_tasks > 0 
      ? ((taskStats.completed_tasks / taskStats.total_tasks) * 100).toFixed(2) + '%'
      : '0%',
    overdue_tasks: taskStats.overdue_tasks,
    unassigned_tasks: taskStats.unassigned_tasks
  },
  task_statistics: taskStats,
  status_breakdown: statusBreakdown,
  team_performance: teamPerformance,
  priority_breakdown: priorityBreakdown
};

return { json: reportData };

